-- Pre-allocate extents:
ALTER TABLE <hot_table> ALLOCATE EXTENT (SIZE 100M);
-- Or grow proactively:
BEGIN DBMS_SPACE.EXTEND_SEGMENT('<schema>', '<table>'); END;
/
-- Check current extent sizing:
SELECT segment_name, bytes/1024/1024 MB, extents, next_extent/1024/1024 next_mb FROM dba_segments WHERE segment_name = '<table>';

-- View execution plan:
SELECT * FROM TABLE(DBMS_XPLAN.DISPLAY_AWR('ahrw3nkrzt4ar'));
-- Run SQL Tuning Advisor:
DECLARE l_task VARCHAR2(100);
BEGIN
  l_task := DBMS_SQLTUNE.CREATE_TUNING_TASK(sql_id=>'ahrw3nkrzt4ar', scope=>DBMS_SQLTUNE.SCOPE_COMPREHENSIVE, time_limit=>60, task_name=>'TUNE_ahrw3nkrzt4ar');
  DBMS_SQLTUNE.EXECUTE_TUNING_TASK(task_name=>'TUNE_ahrw3nkrzt4ar');
END;
/
SELECT DBMS_SQLTUNE.REPORT_TUNING_TASK('TUNE_ahrw3nkrzt4ar') FROM dual;
